--
-- Name: user_registration_request; Type: TABLE; Schema: nhahocduong; Owner: postgres
--

CREATE TABLE nhahocduong.user_registration_request (
    id bigint NOT NULL,
    username character varying NOT NULL,
    password_hash character varying(100) NOT NULL,
    first_name character varying NOT NULL,
    last_name character varying NOT NULL,
    email character varying NOT NULL,
    phone_number character varying,
    birthdate date,
    organization_id bigint,
    requested_role_code character varying DEFAULT 'MANAGER'::character varying NOT NULL,
    status character varying(20) DEFAULT 'PENDING'::character varying NOT NULL,
    submitted_at timestamp without time zone DEFAULT now() NOT NULL,
    reviewed_at timestamp without time zone,
    reviewed_by bigint,
    review_note text,
    approved_user_id bigint,
    CONSTRAINT user_registration_request_approved_user_check CHECK (((((status)::text = 'APPROVED'::text) AND (approved_user_id IS NOT NULL)) OR (((status)::text <> 'APPROVED'::text) AND (approved_user_id IS NULL)))),
    CONSTRAINT user_registration_request_manager_role_check CHECK (((requested_role_code)::text = 'MANAGER'::text)),
    CONSTRAINT user_registration_request_review_check CHECK (((((status)::text = 'PENDING'::text) AND (reviewed_at IS NULL) AND (reviewed_by IS NULL)) OR ((status)::text = 'CANCELLED'::text) OR (((status)::text = ANY ((ARRAY['APPROVED'::character varying, 'REJECTED'::character varying])::text[])) AND (reviewed_at IS NOT NULL) AND (reviewed_by IS NOT NULL)))),
    CONSTRAINT user_registration_request_status_check CHECK (((status)::text = ANY ((ARRAY['PENDING'::character varying, 'APPROVED'::character varying, 'REJECTED'::character varying, 'CANCELLED'::character varying])::text[])))
);


ALTER TABLE nhahocduong.user_registration_request OWNER TO postgres;

